1	/**
2	 * 阶段2：AI 分类 + 证据摘要 + 置信度评分
3	 *
4	 * 输入：阶段1 classify_rules.js 的输出 (classified_rules_*.json)
5	 * 输出：全量 P0-P4 名单 + 证据链 + 置信度 + 两遍差异报告 + 自检清单
6	 *
7	 * 两遍法：
8	 *   第一遍 — metadata 粗筛（unread/recent/消息方向/沉默天数）
9	 *   第二遍 — latestMessageContent 内容信号修正
10	 */
11	
12	const fs = require("fs");
13	const path = require("path");
14	
15	const DATA_DIR = path.join(__dirname, "..", "data");
16	const inputFile = path.join(DATA_DIR, "classified_rules_2026-05-04T07-48-48.json");
17	const outputFile = path.join(
18	  DATA_DIR,
19	  `classified_ai_${new Date().toISOString().replace(/[:.]/g, "-")}.json`
20	);
21	
22	// ============================================================
23	// 升级信号关键词
24	// ============================================================
25	const UPGRADE_SIGNALS = {
26	  orderReady: {
27	    pattern:
28	      /下单|place order|make order|сделаем заказ|确认订单|confirm order|proceed with order|create.*order|ready.*order|start.*order/i,
29	    weight: 2,
30	    desc: "下单信号",
31	  },
32	  piSent: {
33	    pattern: /PI|proforma invoice|形式发票|发票.*已发|PI.*sent|send.*PI/i,
34	    weight: 2,
35	    desc: "PI相关",
36	  },
37	  payment: {
38	    pattern:
39	      /付款|payment|deposit|定金|预付|advance|bank transfer|TT|wire transfer|paypal|paid|已付款|balance/i,
40	    weight: 2,
41	    desc: "付款相关",
42	  },
43	  addressGiven: {
44	    pattern:
45	      /地址|address|delivery.*address|shipping.*address|收货地址|deliver to|ship to|postal code|zip code|country.*city|port of|destination/i,
46	    weight: 1,
47	    desc: "地址已给",
48	  },
49	  quantityConfirmed: {
50	    pattern:
51	      /(\d+)\s*(pieces|pcs|units|件|个|套|sets).*(?:确认|confirm|need|want|order|需要|要)/i,
52	    weight: 1,
53	    desc: "数量讨论",
54	  },
55	  samples: {
56	    pattern:
57	      /样品|sample|打样|prototype|寄样|send.*sample|sample.*ready|sample.*sent/i,
58	    weight: 1,
59	    desc: "样品阶段",
60	  },
61	  priceDiscussion: {
62	    pattern:
63	      /价格|price|quote|报价|quotation|USD|FOB|CIF|DDP|EXW|运费|shipping.*cost|freight|每件|per piece|unit price/i,
64	    weight: 1,
65	    desc: "价格/运费讨论",
66	  },
67	  productSelection: {
68	    pattern:
69	      /(CO-\d+|PO-\d+|[A-Z]{2}-\d{2})|选款|choose|select|pick|model|style|款式|颜色|color|size|尺码|码数/i,
70	    weight: 1,
71	    desc: "选款/产品讨论",
72	  },
73	  partnerConsult: {
74	    pattern:
75	      /partner|商量|consult|discuss.*partner|合伙|определюсь с партнером|wait.*partner|check.*partner/i,
76	    weight: 1,
77	    desc: "等合伙人商量",
78	  },
79	};
80	
81	// ============================================================
82	// 降级信号关键词
83	// ============================================================
84	const DOWNGRADE_SIGNALS = {
85	  templateQuestion: {
86	    pattern:
87	      /what is your|how many|MOQ|minimum order|what country|please let me know|feel free to|could you please|may I know/i,
88	    desc: "模板提问式消息",
89	  },
90	  genericGreeting: {
91	    pattern:
92	      /^(hi|hello|hey|dear)\b.{0,30}$/i,
93	    desc: "仅打招呼无实质",
94	  },
95	  onlyEmoji: {
96	    pattern: /^\/:[\w]+\.?\s*(\/:[\w]+\.?\s*)*$/,
97	    desc: "仅表情",
98	  },
99	};
100	
101	// ============================================================
102	// 核心市场（高优先级）
103	// ============================================================
104	const CORE_MARKETS = [
105	  "SD", "EG", "CD", "ZM", "CI", "SA", "AE", // 主市场
106	  "IQ", "OM", "BH", "KW", "QA", "JO", "LY", "LB", // 中东扩展
107	  "GH", "SN", "KE", "TZ", "CM", "ML", "GN", "ZW", // 非洲扩展
108	];
109	
110	// ============================================================
111	// 分析函数
112	// ============================================================
113	
114	function detectSignals(text) {
115	  if (!text) return { upgrades: [], downgrades: [] };
116	  const upgrades = [];
117	  const downgrades = [];
118	
119	  for (const [key, sig] of Object.entries(UPGRADE_SIGNALS)) {
120	    if (sig.pattern.test(text)) {
121	      upgrades.push({ key, weight: sig.weight, desc: sig.desc });
122	    }
123	  }
124	
125	  for (const [key, sig] of Object.entries(DOWNGRADE_SIGNALS)) {
126	    if (sig.pattern.test(text)) {
127	      downgrades.push({ key, desc: sig.desc });
128	    }
129	  }
130	
131	  return { upgrades, downgrades };
132	}
133	
134	function isOurMessage(c) {
135	  return c.latestType === "send";
136	}
137	
138	function isCustomerMessage(c) {
139	  return c.latestType === "received";
140	}
141	
142	function isPureSystemOrBot(c) {
143	  // 纯系统消息 + 无实质对话
144	  if (c.flags.isLatestSystemMsg) return true;
145	  if (c.direction.total <= 1 && isOurMessage(c) && !c.latestMsg) return true;
146	  return false;
147	}
148	
149	function classifyCustomer(c) {
150	  const signals = detectSignals(c.latestMsg);
151	  const totalUpgradeWeight = signals.upgrades.reduce((s, u) => s + u.weight, 0);
152	  const hasDowngrade = signals.downgrades.length > 0;
153	  const isCore = CORE_MARKETS.includes(c.country);
154	  const ourMsg = isOurMessage(c);
155	  const custMsg = isCustomerMessage(c);
156	  const silenceDays = c.silenceDays;
157	
158	  let priority = c._rulePriority; // 从规则优先级开始
159	  let confidence = 3; // 1=低 2=中 3=高
160	  let evidence = [];
161	  let checks = [];
162	  let actions = [];
163	
164	  // ---- 第一遍：Metadata 粗筛 ----
165	
166	  // 纯系统消息/机器人 → 大幅降级
167	  if (isPureSystemOrBot(c)) {
168	    if (silenceDays > 30) {
169	      priority = "P4";
170	      evidence.push("纯系统消息+超30天无互动→P4");
171	      confidence = 3;
172	    } else if (silenceDays > 14) {
173	      priority = "P3";
174	      evidence.push("纯系统消息+超14天无互动→P3");
175	      confidence = 2;
176	    } else {
177	      priority = "P3";
178	      evidence.push("纯系统消息+近期互动→P3（需确认是否为真人对话）");
179	      confidence = 1;
180	    }
181	    checks.push("系统消息确认");
182	    return { priority, confidence, evidence, checks, actions, tier: "C" };
183	  }
184	
185	  // hasAddress + 我方追问地址/运费 → 谈判活跃
186	  if (c.flags.hasAddress && totalUpgradeWeight >= 2 && silenceDays <= 5) {
187	    priority = "P0";
188	    evidence.push("地址已确认+多重升级信号+近期活跃→P0");
189	    confidence = 2;
190	  }
191	  // 强升级信号 (PI/付款/下单)
192	  else if (totalUpgradeWeight >= 3 && silenceDays <= 7) {
193	    priority = "P0";
194	    evidence.push(`强升级信号(权重${totalUpgradeWeight})+${silenceDays}天内→P0`);
195	    confidence = 2;
196	  }
197	  // 中强升级 + 核心市场
198	  else if (totalUpgradeWeight >= 2 && silenceDays <= 7 && isCore) {
199	    priority = "P1";
200	    evidence.push(`升级信号(权重${totalUpgradeWeight})+核心市场+${silenceDays}天内→P1`);
201	    confidence = 2;
202	  }
203	  // 中强升级
204	  else if (totalUpgradeWeight >= 2 && silenceDays <= 7) {
205	    priority = "P1";
206	    evidence.push(`升级信号(权重${totalUpgradeWeight})+${silenceDays}天内→P1`);
207	    confidence = 2;
208	  }
209	  // 未读消息 + 我方发送 → 需要看是否有客户之前发过消息
210	  else if (c.isUnread && ourMsg && silenceDays <= 3) {
211	    priority = "P1";
212	    evidence.push(`未读消息+我方最近发送+${silenceDays}天→P1（需确认客户是否有回应）`);
213	    confidence = 1;
214	  }
215	  // 未读消息 + 客户发送 → 可能重要
216	  else if (c.isUnread && custMsg) {
217	    priority = "P0";
218	    evidence.push("未读消息+客户发送→P0（客户主动联系，高优先）");
219	    confidence = 2;
220	  }
221	  // 有地址标记 + 近期活跃
222	  else if (c.flags.hasAddress && silenceDays <= 7) {
223	    priority = "P1";
224	    evidence.push(`有地址+${silenceDays}天内活跃→P1`);
225	    confidence = 2;
226	  }
227	  // 核心市场 + 近期活跃 + 有实质内容
228	  else if (isCore && silenceDays <= 7 && c.latestMsg && c.latestMsg.length > 30) {
229	    priority = "P1";
230	    evidence.push(`核心市场+${silenceDays}天内活跃+有实质内容→P1`);
231	    confidence = 2;
232	  }
233	  // needLookback → 最后一条是表情/单字，数据不够
234	  else if (c.flags.needLookback) {
235	    priority = "P2";
236	    evidence.push("最后消息为表情/单字+无法判断真实阶段→暂P2");
237	    confidence = 1;
238	  }
239	  // 我方模板提问 + 客户沉默>3天 → 降级
240	  else if (hasDowngrade && ourMsg && silenceDays > 3) {
241	    if (silenceDays > 14) {
242	      priority = "P3";
243	      evidence.push("模板提问+客户沉默超14天→P3");
244	      confidence = 2;
245	    } else {
246	      priority = "P2";
247	      evidence.push("模板提问+客户沉默${silenceDays}天→P2");
248	      confidence = 2;
249	    }
250	  }
251	  // 长期沉默
252	  else if (silenceDays > 60) {
253	    priority = "P4";
254	    evidence.push(`沉默${silenceDays}天→P4`);
255	    confidence = 3;
256	  } else if (silenceDays > 30) {
257	    priority = "P3";
258	    evidence.push(`沉默${silenceDays}天→P3`);
259	    confidence = 2;
260	  }
261	  // 我方消息 + 客户从未回复
262	  else if (ourMsg && c.direction.total <= 1 && silenceDays > 7) {
263	    priority = "P3";
264	    evidence.push("我方单向发送+客户无回应超7天→P3");
265	    confidence = 2;
266	  }
267	  // 默认：保持规则分类 + 降低置信度
268	  else {
269	    evidence.push("信号不足，维持规则分类");
270	    confidence = 1;
271	  }
272	
273	  // ---- 修正不合理分类 ----
274	  // 如果规则分了P0但最新消息只是我方模板提问 → 降级
275	  if (c._rulePriority === "P0" && hasDowngrade && ourMsg) {
276	    if (silenceDays <= 3) {
277	      priority = "P1";
278	      evidence.push("规则P0但实为我方模板提问→降为P1");
279	      confidence = 2;
280	    } else {
281	      priority = "P2";
282	      evidence.push("规则P0但实为我方模板提问+已沉默→降为P2");
283	      confidence = 2;
284	    }
285	  }
286	
287	  // 如果规则分了P1但实际是需要往前看才能判断 → 降低置信度
288	  if (c._rulePriority === "P1" && c.flags.needLookback && !totalUpgradeWeight) {
289	    priority = "P2";
290	    evidence.push("规则P1但最后消息为表情/单字+无升级信号→降为P2");
291	    confidence = 1;
292	  }
293	
294	  // ---- 构建证据链 ----
295	  checks.push(`系统消息:${c.flags.isLatestSystemMsg ? "是" : "否"}`);
296	  checks.push(`产品代码:${c.flags.hasProductSelection ? "有" : "无"}`);
297	  checks.push(`地址:${c.flags.hasAddress ? "有" : "无"}`);
298	  checks.push(`消息数:${c.direction.total}`);
299	  checks.push(`升级信号:${signals.upgrades.map((u) => u.desc).join("+") || "无"}`);
300	  checks.push(`降级信号:${signals.downgrades.map((d) => d.desc).join("+") || "无"}`);
301	
302	  // 置信度标记
303	  const stars = confidence === 3 ? "★★★" : confidence === 2 ? "★★☆" : "★☆☆";
304	
305	  // 层级
306	  let tier;
307	  if (priority === "P0") tier = "A";
308	  else if (priority === "P1") tier = "B";
309	  else tier = "C";
310	
311	  return {
312	    priority,
313	    confidence,
314	    stars,
315	    evidence,
316	    checks,
317	    actions,
318	    tier,
319	    upgradeSignals: signals.upgrades,
320	    downgradeSignals: signals.downgrades,
321	  };
322	}
323	
324	// ============================================================
325	// 主流程
326	// ============================================================
327	
328	console.log("=".repeat(60));
329	console.log("阶段2：AI 分类 + 证据摘要 + 置信度评分");
330	console.log("=".repeat(60));
331	
332	const data = JSON.parse(fs.readFileSync(inputFile, "utf8"));
333	const needAI = data.customers.filter((c) => c._needAI);
334	const deterministic = data.customers.filter((c) => !c._needAI);
335	
336	console.log(`\n总客户: ${data.customers.length}`);
337	console.log(`确定性分类(阶段1): ${deterministic.length}`);
338	console.log(`需AI复核: ${needAI.length}`);
339	
340	// 对needAI客户执行AI分类
341	const aiResults = [];
342	const diffReport = [];
343	const lowConfidence = [];
344	
345	for (const c of needAI) {
346	  const result = classifyCustomer(c);
347	
348	  const aiEntry = {
349	    ...c,
350	    _aiPriority: result.priority,
351	    _aiConfidence: result.confidence,
352	    _aiStars: result.stars,
353	    _aiEvidence: result.evidence,
354	    _aiChecks: result.checks,
355	    _aiTier: result.tier,
356	    _aiUpgrades: result.upgradeSignals,
357	    _aiDowngrades: result.downgradeSignals,
358	    // 最终分类（AI修正后）
359	    priority: result.priority,
360	    tier: result.tier,
361	    reasons: result.evidence,
362	  };
363	
364	  aiResults.push(aiEntry);
365	
366	  // 差异报告
367	  if (result.priority !== c._rulePriority) {
368	    diffReport.push({
369	      name: c.name,
370	      country: c.countryCode,
371	      rulePriority: c._rulePriority,
372	      aiPriority: result.priority,
373	      reason: result.evidence.join(" | "),
374	      confidence: result.stars,
375	    });
376	  }
377	
378	  // 低置信度清单
379	  if (result.confidence <= 1) {
380	    lowConfidence.push({
381	      name: c.name,
382	      country: c.countryCode,
383	      priority: result.priority,
384	      reason: result.evidence.join(" | "),
385	      issue: "需要完整对话数据才能准确判断",
386	    });
387	  }
388	}
389	
390	// ---- 合并确定性分类和AI分类 ----
391	const allClassified = [
392	  ...deterministic.map((c) => ({
393	    ...c,
394	    _aiPriority: c.priority,
395	    _aiConfidence: 3,
396	    _aiStars: "★★★",
397	    _aiEvidence: c._ruleReasons || c.reasons,
398	  })),
399	  ...aiResults,
400	];
401	
402	// ---- 统计 ----
403	const byPriority = {};
404	allClassified.forEach((c) => {
405	  const p = c.priority;
406	  byPriority[p] = (byPriority[p] || 0) + 1;
407	});
408	
409	console.log("\n--- AI分类后分布 ---");
410	for (const [p, count] of Object.entries(byPriority).sort()) {
411	  console.log(`  ${p}: ${count}`);
412	}
413	
414	console.log(`\n--- 差异报告（阶段1规则 vs 阶段2 AI）---`);
415	console.log(`差异数: ${diffReport.length}`);
416	if (diffReport.length === 0) {
417	  console.log("  ⚠️ 差异为0！第二遍可能未真正执行。请检查。");
418	} else {
419	  diffReport.forEach((d) => {
420	    console.log(
421	      `  ${d.rulePriority}→${d.aiPriority} | ${d.name} (${d.country}) | ${d.confidence} | ${d.reason.slice(0, 80)}`
422	    );
423	  });
424	}
425	
426	console.log(`\n--- ★☆☆ 低置信度清单（需用户确认）---`);
427	console.log(`数量: ${lowConfidence.length}`);
428	lowConfidence.forEach((l) => {
429	  console.log(`  ${l.name} (${l.country}) | ${l.priority} | ${l.issue}`);
430	});
431	
432	// ---- 自检清单 ----
433	console.log("\n--- 自检清单 ---");
434	const checklist = [];
435	// 1. 检查latestMessageContent为空的
436	const emptyMsg = allClassified.filter(
437	  (c) => !c.latestMessageContent || c.latestMessageContent.trim() === ""
438	);
439	checklist.push({
440	  item: "latestMessageContent为空的条目",
441	  status: emptyMsg.length > 0 ? "⚠️ 有" : "✓ 无",
442	  count: emptyMsg.length,
443	  names: emptyMsg.map((c) => c.name).slice(0, 5),
444	});
445	
446	// 2. 检查P0但消息都是我方发的
447	const p0OurMsg = allClassified.filter(
448	  (c) => c.priority === "P0" && c.latestMessageType === "send" && c.direction.total <= 1
449	);
450	checklist.push({
451	  item: "P0但仅我方单条消息（可能虚高）",
452	  status: p0OurMsg.length > 0 ? "⚠️ 有" : "✓ 无",
453	  count: p0OurMsg.length,
454	  names: p0OurMsg.map((c) => c.name),
455	});
456	
457	// 3. 检查纯系统消息被分为P0/P1的
458	const sysHigh = allClassified.filter(
459	  (c) =>
460	    (c.priority === "P0" || c.priority === "P1") && c.flags?.isLatestSystemMsg
461	);
462	checklist.push({
463	  item: "P0/P1中仍有纯系统消息",
464	  status: sysHigh.length > 0 ? "⚠️ 有" : "✓ 无",
465	  count: sysHigh.length,
466	  names: sysHigh.map((c) => c.name),
467	});
468	
469	// 4. 表情/单字导致误判
470	const emojiIssue = allClassified.filter(
471	  (c) =>
472	    (c.priority === "P0" || c.priority === "P1") && c.flags?.needLookback
473	);
474	checklist.push({
475	  item: "P0/P1中最后消息为表情/单字（需往前看）",
476	  status: emojiIssue.length > 0 ? "⚠️ 有" : "✓ 无",
477	  count: emojiIssue.length,
478	  names: emojiIssue.map((c) => c.name),
479	});
480	
481	// 5. P0超过5天无互动
482	const p0Old = allClassified.filter(
483	  (c) => c.priority === "P0" && c._silenceDays > 5
484	);
485	checklist.push({
486	  item: "P0但超5天无互动",
487	  status: p0Old.length > 0 ? "⚠️ 有" : "✓ 无",
488	  count: p0Old.length,
489	  names: p0Old.map((c) => c.name),
490	});
491	
492	checklist.forEach((cl) => {
493	  console.log(`  [${cl.status}] ${cl.item}: ${cl.count}条`);
494	  if (cl.names && cl.names.length > 0 && cl.names.length <= 10) {
495	    console.log(`    → ${cl.names.join(", ")}`);
496	  }
497	});
498	
499	// ---- 输出 ----
500	const output = {
501	  classifiedAt: new Date().toISOString(),
502	  source: path.basename(inputFile),
503	  method: "AI两遍法（metadata粗筛 + 内容信号修正）",
504	  stats: {
505	    total: allClassified.length,
506	    byPriority,
507	    needAI: needAI.length,
508	    deterministic: deterministic.length,
509	    diffCount: diffReport.length,
510	    lowConfidenceCount: lowConfidence.length,
511	    dataLimitation:
512	      "CDP未抓取完整对话历史，仅基于latestMessageContent+metadata。消息数标记为0为抓取限制，非实际无消息。",
513	  },
514	  diffReport,
515	  lowConfidence,
516	  checklist,
517	  customers: allClassified,
518	};
519	
520	fs.writeFileSync(outputFile, JSON.stringify(output, null, 2));
521	console.log(`\n✅ 输出: ${outputFile}`);
522	console.log(`   总客户: ${allClassified.length}`);
523	console.log(`   差异: ${diffReport.length} | 低置信度: ${lowConfidence.length}`);
524

