/**
 * 阶段2：AI 分类 + 证据摘要 + 置信度评分
 *
 * 输入：阶段1 classify_rules.js 的输出 (classified_rules_*.json)
 * 输出：全量 P0-P4 名单 + 证据链 + 置信度 + 两遍差异报告 + 自检清单
 *
 * 两遍法：
 *   第一遍 — metadata 粗筛（unread/recent/消息方向/沉默天数）
 *   第二遍 — latestMessageContent 内容信号修正
 */

const fs = require("fs");
const path = require("path");

const DATA_DIR = path.join(__dirname, "..", "data");

// 找最新的 classified_rules 文件
const files = fs.readdirSync(DATA_DIR).filter(f => f.startsWith("classified_rules_") && f.endsWith(".json"));
files.sort();
const inputFile = path.join(DATA_DIR, files[files.length - 1]);

const outputFile = path.join(
  DATA_DIR,
  `classified_ai_${new Date().toISOString().replace(/[:.]/g, "-")}.json`
);

console.log(`输入文件: ${path.basename(inputFile)}`);

// ============================================================
// 升级信号关键词
// ============================================================
const UPGRADE_SIGNALS = {
  orderReady: {
    pattern: /下单|place order|make order|сделаем заказ|确认订单|confirm order|proceed with order|create.*order|ready.*order|start.*order|send.*order|order.*now/i,
    weight: 2,
    desc: "下单信号",
  },
  piSent: {
    pattern: /PI|proforma invoice|形式发票|发票.*已发|PI.*sent|send.*PI|invoice/i,
    weight: 2,
    desc: "PI相关",
  },
  payment: {
    pattern: /付款|payment|deposit|定金|预付|advance|bank transfer|TT|wire transfer|paypal|paid|已付款|balance|payment.*link|支付链接|proceed.*payment|payment.*completed/i,
    weight: 2,
    desc: "付款相关",
  },
  addressConfirmed: {
    pattern: /地址|address|delivery.*address|shipping.*address|收货地址|deliver to|ship to|postal code|zip code|country.*city|port of|destination|warehouse|仓库|freight forwarder|forwarder/i,
    weight: 1,
    desc: "地址已给",
  },
  quantityDiscussed: {
    pattern: /(\d+)\s*(pieces|pcs|units|件|个|套|sets).*(?:确认|confirm|need|want|order|需要|要|total)|how many|كم قطعة/i,
    weight: 1,
    desc: "数量讨论",
  },
  samples: {
    pattern: /样品|sample|打样|prototype|寄样|send.*sample|sample.*ready|sample.*sent|check.*quality|actual.*photo/i,
    weight: 1,
    desc: "样品/产品确认",
  },
  priceDiscussion: {
    pattern: /价格|price|quote|报价|quotation|USD|FOB|CIF|DDP|EXW|运费|shipping.*cost|freight|每件|per piece|unit price|total.*amount|order.*amount|total.*order/i,
    weight: 1,
    desc: "价格/运费讨论",
  },
  productSelection: {
    pattern: /(CO-\d+|PO-\d+|[A-Z]{2}-\d{2})|选款|choose|select|pick|model|style|款式|颜色|color|size|尺码|码数|which.*style/i,
    weight: 1,
    desc: "选款/产品讨论",
  },
  partnerConsult: {
    pattern: /partner|商量|consult|discuss.*partner|合伙|определюсь с партнером|wait.*partner|check.*partner/i,
    weight: 1,
    desc: "等合伙人商量",
  },
  shipmentReady: {
    pattern: /shipp|shipment|发货|send.*goods|物流|delivery|send.*cargo|arrange.*shipment|as soon as possible.*ship/i,
    weight: 1,
    desc: "发货相关",
  },
  productPhotos: {
    pattern: /photo|picture|image|图片|照片|check.*quality|catalog|目录|design.*catalog/i,
    weight: 1,
    desc: "产品图片/目录",
  },
};

// ============================================================
// 降级信号
// ============================================================
const DOWNGRADE_SIGNALS = {
  templateQuestion: {
    pattern: /what is your\b|how many\b|MOQ|minimum order|what country\b|please let me know\b|feel free to\b|could you please|may I know/i,
    desc: "模板提问式消息",
  },
  genericGreeting: {
    pattern: /^(hi|hello|hey|dear|hola|bonjour|salut)\b.{0,30}$/i,
    desc: "仅打招呼无实质",
  },
  onlyEmojiOrShort: {
    pattern: /^\[商品\]$|^\[文件\]$|^\[图片\]$/,
    desc: "仅商品/文件卡片",
  },
};

// ============================================================
// 数据归一化（关键修复：脚本字段名 vs 实际数据结构）
// ============================================================
function normalize(c) {
  const msg = c.latestMessageContent || c.message || "";
  const msgType = c.latestMessageType || "";
  const msgDir = c._messageDirection || { total: 1, latestDirection: msgType };
  const flags = c._flags || {};
  const silenceDays = c._silenceDays != null ? c._silenceDays : (c.daysAgo || 0);

  return {
    ...c,
    // 统一字段名
    _n_msg: msg,
    _n_msgType: msgType,
    _n_isSend: msgType === "send",
    _n_isReceived: msgType === "received",
    _n_total: msgDir.total || 1,
    _n_silenceDays: silenceDays,
    _n_isUnread: c.isUnread || false,
    _n_hasAddress: flags.hasAddress || false,
    _n_needLookback: flags.needLookback || false,
    _n_isSystemMsg: flags.isLatestSystemMsg || false,
    _n_hasProductCode: flags.hasProductSelection || false,
    _n_countryCode: c.countryCode || "",
  };
}

// ============================================================
// 信号检测
// ============================================================
function detectSignals(text) {
  if (!text) return { upgrades: [], downgrades: [] };
  const upgrades = [];
  const downgrades = [];

  for (const [key, sig] of Object.entries(UPGRADE_SIGNALS)) {
    if (sig.pattern.test(text)) {
      upgrades.push({ key, weight: sig.weight, desc: sig.desc });
    }
  }

  for (const [key, sig] of Object.entries(DOWNGRADE_SIGNALS)) {
    if (sig.pattern.test(text)) {
      downgrades.push({ key, desc: sig.desc });
    }
  }

  return { upgrades, downgrades };
}

// ============================================================
// 核心市场
// ============================================================
const CORE_MARKETS = new Set([
  "SD", "EG", "CD", "ZM", "CI", "SA", "AE",
  "IQ", "OM", "BH", "KW", "QA", "JO", "LY", "LB",
  "GH", "SN", "KE", "TZ", "CM", "ML", "GN", "ZW",
]);

// ============================================================
// 单个客户 AI 分类
// ============================================================
function classifyCustomer(c) {
  const n = normalize(c);
  const text = n._n_msg || "";
  const signals = detectSignals(text);
  const totalWeight = signals.upgrades.reduce((s, u) => s + u.weight, 0);
  const hasDowngrade = signals.downgrades.length > 0;
  const silenceDays = n._n_silenceDays;
  const isUnread = n._n_isUnread;
  const isSend = n._n_isSend;
  const isReceived = n._n_isReceived;

  let priority = n._rulePriority || "P2";
  let confidence = 1;
  const evidence = [];
  const checks = [];

  // ---- 第一遍：Metadata 粗筛 ----

  // 今天有新消息 + 客户发送 + 未读 → 最高优先级
  if (isUnread && isReceived && silenceDays <= 1) {
    // 第二遍检查内容信号
    if (totalWeight >= 3) {
      priority = "P0";
      evidence.push(`未读+客户消息+强升级信号(权重${totalWeight})→P0`);
      confidence = 2;
    } else if (totalWeight >= 1) {
      priority = "P0";
      evidence.push(`未读+客户消息+升级信号→P0`);
      confidence = 2;
    } else {
      priority = "P1";
      evidence.push("未读+客户消息+无明确升级信号→P1（需看历史判断）");
      confidence = 1;
    }
  }
  // 今天有消息 + 我方发送 + 有升级信号
  else if (isSend && silenceDays <= 1 && totalWeight >= 2) {
    priority = "P0";
    evidence.push(`今日我方消息+强升级信号(权重${totalWeight})→P0`);
    confidence = 2;
  }
  // 未读+客户消息+稍旧（2-3天）
  else if (isUnread && isReceived && silenceDays <= 3) {
    priority = totalWeight >= 2 ? "P0" : "P1";
    evidence.push(`未读+客户${silenceDays}天前消息+权重${totalWeight}→${priority}`);
    confidence = 2;
  }
  // 未读+客户消息+较旧（4-5天）
  else if (isUnread && isReceived && silenceDays <= 7) {
    priority = totalWeight >= 2 ? "P1" : "P2";
    evidence.push(`未读+客户${silenceDays}天前消息→${priority}`);
    confidence = 1;
  }
  // 我方最近发送 + 强升级信号
  else if (isSend && silenceDays <= 7 && totalWeight >= 3) {
    priority = "P0";
    evidence.push(`强升级信号(权重${totalWeight})+${silenceDays}天内→P0`);
    confidence = 2;
  }
  // 我方最近发送 + 中等信号
  else if (isSend && silenceDays <= 7 && totalWeight >= 2) {
    priority = "P1";
    evidence.push(`升级信号(权重${totalWeight})+${silenceDays}天内→P1`);
    confidence = 2;
  }
  // needLookback（最后消息为商品卡/表情/文件等，需往前看）
  else if (n._n_needLookback) {
    if (silenceDays <= 3) {
      priority = "P1";
      evidence.push("最后消息为卡片/表情，需往前看判断→暂P1");
      confidence = 1;
    } else {
      priority = "P2";
      evidence.push(`最后消息为卡片/表情+${silenceDays}天→暂P2`);
      confidence = 1;
    }
  }
  // 有地址 + 近期
  else if (n._n_hasAddress && silenceDays <= 7) {
    priority = totalWeight >= 1 ? "P1" : "P2";
    evidence.push(`有地址+${silenceDays}天→${priority}`);
    confidence = 2;
  }
  // 模板提问 + 沉默
  else if (hasDowngrade && isSend && silenceDays > 3) {
    priority = silenceDays > 14 ? "P3" : "P2";
    evidence.push(`模板提问+客户沉默${silenceDays}天→${priority}`);
    confidence = 2;
  }
  // 长期沉默
  else if (silenceDays > 90) {
    priority = "P4";
    evidence.push(`沉默${silenceDays}天→P4`);
    confidence = 3;
  }
  else if (silenceDays > 30) {
    priority = "P3";
    evidence.push(`沉默${silenceDays}天→P3`);
    confidence = 2;
  }
  // 我方单向，客户从未回复
  else if (isSend && silenceDays > 7 && n._n_total <= 1) {
    priority = "P3";
    evidence.push(`我方单向发送+客户无回应超7天→P3`);
    confidence = 2;
  }
  // nothing found, keep rule priority with low confidence
  else {
    evidence.push("信号不足，维持规则分类");
    confidence = 1;
  }

  // ---- 修正：检查规则分类是否明显错误 ----
  // 规则标P3但silenceDays=0且有未读消息 → 升级
  if (n._rulePriority === "P3" && silenceDays <= 1 && isUnread && isReceived) {
    if (totalWeight >= 2) {
      priority = "P0";
      evidence.push("【修正】规则P3但今天有未读客户消息+升级信号→P0");
      confidence = 2;
    } else {
      priority = "P1";
      evidence.push("【修正】规则P3但今天有未读客户消息→P1");
      confidence = 2;
    }
  }
  // 规则标P4但我方今天刚发了消息
  if (n._rulePriority === "P4" && silenceDays <= 1 && isSend) {
    priority = "P2";
    evidence.push("【修正】规则P4但我方今日刚发消息→P2（观察中）");
    confidence = 2;
  }

  // ---- 构建检查清单 ----
  checks.push(`系统消息:${n._n_isSystemMsg ? "是" : "否"}`);
  checks.push(`产品代码:${n._n_hasProductCode ? "有" : "无"}`);
  checks.push(`地址:${n._n_hasAddress ? "有" : "无"}`);
  checks.push(`消息方向:${isSend ? "我方" : isReceived ? "客户" : "未知"}`);
  checks.push(`消息数(快照):${n._n_total}`);
  checks.push(`升级:${signals.upgrades.map(u => u.desc).join("+") || "无"}`);
  checks.push(`降级:${signals.downgrades.map(d => d.desc).join("+") || "无"}`);

  const stars = confidence >= 3 ? "★★★" : confidence >= 2 ? "★★☆" : "★☆☆";

  let tier;
  if (priority === "P0") tier = "S";
  else if (priority === "P1") tier = "A";
  else if (priority === "P2") tier = "B";
  else tier = "C";

  return {
    priority,
    confidence,
    stars,
    evidence,
    checks,
    tier,
    upgradeSignals: signals.upgrades,
    downgradeSignals: signals.downgrades,
    totalWeight,
  };
