  }
  // 今天有消息 + 我方发送 + 有升级信号
  else if (isSend && silenceDays <= 1 && totalWeight >= 2) {
    priority = "P0";
    evidence.push(`今日我方消息+强升级信号(权重${totalWeight})→P0`);
    confidence = 2;
  }
  // 未读+客户消息+稍旧（2-3天）
  else if (isUnread && isReceived && silenceDays <= 3) {
    priority = totalWeight >= 2 ? "P0" : "P1";
    evidence.push(`未读+客户${silenceDays}天前消息+权重${totalWeight}→${priority}`);
    confidence = 2;
  }
  // 未读+客户消息+较旧（4-5天）
  else if (isUnread && isReceived && silenceDays <= 7) {
    priority = totalWeight >= 2 ? "P1" : "P2";
    evidence.push(`未读+客户${silenceDays}天前消息→${priority}`);
    confidence = 1;
  }
  // 我方最近发送 + 强升级信号
  else if (isSend && silenceDays <= 7 && totalWeight >= 3) {
    priority = "P0";
    evidence.push(`强升级信号(权重${totalWeight})+${silenceDays}天内→P0`);
    confidence = 2;
  }
  // 我方最近发送 + 中等信号
  else if (isSend && silenceDays <= 7 && totalWeight >= 2) {
    priority = "P1";
    evidence.push(`升级信号(权重${totalWeight})+${silenceDays}天内→P1`);
    confidence = 2;
  }
  // needLookback（最后消息为商品卡/表情/文件等，需往前看）
  else if (n._n_needLookback) {
    if (silenceDays <= 3) {
      priority = "P1";
      evidence.push("最后消息为卡片/表情，需往前看判断→暂P1");
      confidence = 1;
    } else {
      priority = "P2";
      evidence.push(`最后消息为卡片/表情+${silenceDays}天→暂P2`);
      confidence = 1;
    }
  }
  // 有地址 + 近期
  else if (n._n_hasAddress && silenceDays <= 7) {
    priority = totalWeight >= 1 ? "P1" : "P2";
    evidence.push(`有地址+${silenceDays}天→${priority}`);
    confidence = 2;
  }
  // 模板提问 + 沉默
  else if (hasDowngrade && isSend && silenceDays > 3) {
    priority = silenceDays > 14 ? "P3" : "P2";
    evidence.push(`模板提问+客户沉默${silenceDays}天→${priority}`);
    confidence = 2;
  }
  // 长期沉默
  else if (silenceDays > 90) {
    priority = "P4";
    evidence.push(`沉默${silenceDays}天→P4`);
    confidence = 3;
  }
  else if (silenceDays > 30) {
    priority = "P3";
    evidence.push(`沉默${silenceDays}天→P3`);
    confidence = 2;
  }
  // 我方单向，客户从未回复
  else if (isSend && silenceDays > 7 && n._n_total <= 1) {
    priority = "P3";
    evidence.push(`我方单向发送+客户无回应超7天→P3`);
    confidence = 2;
  }
  // nothing found, keep rule priority with low confidence
  else {
    evidence.push("信号不足，维持规则分类");
    confidence = 1;
  }

  // ---- 修正：检查规则分类是否明显错误 ----
  // 规则标P3但silenceDays=0且有未读消息 → 升级
  if (n._rulePriority === "P3" && silenceDays <= 1 && isUnread && isReceived) {
    if (totalWeight >= 2) {
      priority = "P0";
      evidence.push("【修正】规则P3但今天有未读客户消息+升级信号→P0");
      confidence = 2;
    } else {
      priority = "P1";
      evidence.push("【修正】规则P3但今天有未读客户消息→P1");
      confidence = 2;
    }
  }
  // 规则标P4但我方今天刚发了消息
  if (n._rulePriority === "P4" && silenceDays <= 1 && isSend) {
    priority = "P2";
    evidence.push("【修正】规则P4但我方今日刚发消息→P2（观察中）");
    confidence = 2;
  }

  // ---- 构建检查清单 ----
  checks.push(`系统消息:${n._n_isSystemMsg ? "是" : "否"}`);
  checks.push(`产品代码:${n._n_hasProductCode ? "有" : "无"}`);
  checks.push(`地址:${n._n_hasAddress ? "有" : "无"}`);
  checks.push(`消息方向:${isSend ? "我方" : isReceived ? "客户" : "未知"}`);
  checks.push(`消息数(快照):${n._n_total}`);
  checks.push(`升级:${signals.upgrades.map(u => u.desc).join("+") || "无"}`);
  checks.push(`降级:${signals.downgrades.map(d => d.desc).join("+") || "无"}`);

  const stars = confidence >= 3 ? "★★★" : confidence >= 2 ? "★★☆" : "★☆☆";

  let tier;
  if (priority === "P0") tier = "S";
  else if (priority === "P1") tier = "A";
  else if (priority === "P2") tier = "B";
  else tier = "C";

  return {
    priority,
    confidence,
    stars,
    evidence,
    checks,
    tier,
    upgradeSignals: signals.upgrades,
    downgradeSignals: signals.downgrades,
    totalWeight,
  };
}

