const { chromium } = require('playwright');
const fs = require('fs');
const path = require('path');

const DATA_DIR = path.join(__dirname, '..', 'data');
const CDP_URL = 'http://127.0.0.1:9222';

// ----- helpers -----

const SYSTEM_MSG_PATTERNS = [
  /automatic reception will no longer intervene/i,
  /自动接待将不再触发/,
  /Marco大模型翻译/,
  /阿里国际Marco大模型翻译/,
  /买家有流失风险/,
  /Buyer has churn risk/,
  /一旦离开平台发生纠纷或欺诈/,
  /由于您介入该会话/,
  /Due to your intervention in this session/,
  /AI给您生成了一条回复建议/,
  /反馈/,
];

function isSystemMessage(text) {
  if (!text) return true;
  return SYSTEM_MSG_PATTERNS.some((p) => p.test(text));
}

function isRealContact(name, msg) {
  if (!name || name.length < 2) return false;
  // Filter UI labels and bots
  const skip = ['全部', '消息', 'Assistant Eva', '已折叠', '未读', '已读', '待回复', '待跟进'];
  if (skip.some((s) => name.includes(s))) return false;
  // Filter CSS/symbol noise
  if (/^[\.\#\@\{\}]/.test(name)) return false;
  if (name.length > 60) return false;
  return true;
}

function parseDaysAgo(timeStr) {
  if (!timeStr) return 99;
  if (timeStr.includes(':')) return 0; // today's time like "11:37"
  const m = timeStr.match(/^(\d{4})-(\d{1,2})-(\d{1,2})$/);
  if (m) {
    const d = new Date(parseInt(m[1]), parseInt(m[2]) - 1, parseInt(m[3]));
    return Math.round((Date.now() - d.getTime()) / 86400000);
  }
  return 99;
}

// ----- main -----

(async () => {
  let browser;
  try {
    browser = await chromium.connectOverCDP(CDP_URL);
  } catch (e) {
    console.log('❌ CDP连接失败');
    process.exit(1);
  }

/**
 * 阶段0：数据预处理脚本
 * 输入：data/extracted_*.json 或 data/*全量客户分类.json（CDP 抓取原始数据）
 * 输出：data/cleaned_<timestamp>.json
 *
 * 处理内容：
 * - 检测 latestMessageContent 是否系统消息 → 标记并尝试替换
 * - 检测最后消息是否表情/单字 → 标记 needLookback
 * - 统计消息数 → 标记 needFullRead（≥10 条）
 * - 正则扫描产品代码和地址关键词 → 标记 hasProductSelection / hasAddress
 * - 计算沉默天数
 * - 统计消息方向（如有消息列表数据）
 */

const fs = require('fs');
const path = require('path');

const DATA_DIR = path.join(__dirname, '..', 'data');

// ====== 系统消息模式（来自 business-rules.md） ======
const SYSTEM_MSG_PATTERNS = [
  /automatic reception will no longer intervene/i,
  /自动接待将不再触发/,
  /Marco大模型翻译/,
  /阿里国际Marco大模型翻译/,
  /买家有流失风险/,
  /Buyer has churn risk/,
  /一旦离开平台发生纠纷或欺诈/,
  /由于您介入该会话/,
  /Due to your intervention in this session/,
  /AI给您生成了一条回复建议/,
  /反馈/,
  /You have a visitor\. Follow up with them as soon as possible\./i,
  /This buyer has been pre-screened and has a clear request/i,
  /Since you have read the conversation/i,
];

// ====== 表情/单字模式 ======
const EMOJI_SINGLE_PATTERNS = [
  /^[\u{1F000}-\u{1FFFF}]+$/u,
  /^[\u{2600}-\u{27BF}]+$/u,
  /^[\u{FE00}-\u{FEFF}]+$/u,
  /^[\u{2702}-\u{27B0}]+$/u,
  /^[\u{1F600}-\u{1F64F}]+$/u,
  /^[\u{1F300}-\u{1F5FF}]+$/u,
  /^[\u{1F680}-\u{1F6FF}]+$/u,
  /^[\u{1F900}-\u{1F9FF}]+$/u,
  /^(ok|okay|yes|no|hi|hello|hey|thanks|thx|ty|bye|good|nice|wow)$/i,
  /^[\u{1F600}-\u{1FAFF}\u{2600}-\u{27BF}\u{1F300}-\u{1F5FF}\u{1F680}-\u{1F6FF}\u{1F900}-\u{1F9FF}\u{2700}-\u{27BF}]+$/u,
  /^\[图片\]$/, /^\[商品\]$/, /^\[表情\]$/,
